<div class="grid-2"><div class="card"><h3>Profile Information</h3><form method="post" action="<?= base_url('index.php?route=profile/update') ?>" enctype="multipart/form-data"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><div class="form-group"><label>Name</label><input type="text" name="name" value="<?= e($user['name']) ?>" required></div><div class="form-group"><label>Username</label><input type="text" name="username" value="<?= e($user['username']) ?>" required></div><div class="form-group"><label>Email</label><input type="email" value="<?= e($user['email']) ?>" disabled></div><div class="form-group"><label>Phone</label><input type="text" name="phone" value="<?= e($user['phone']) ?>" required></div><div class="form-group"><label>Avatar</label><input type="file" name="avatar" accept=".jpg,.jpeg,.png,.webp"></div><button class="btn btn-primary" type="submit">Update Profile</button></form></div><div class="card"><h3>Change Password</h3><form method="post" action="<?= base_url('index.php?route=profile/password') ?>"><input type="hidden" name="_csrf" value="<?= csrf_token() ?>"><div class="form-group"><label>Current Password</label><input type="password" name="current_password" required></div><div class="form-group"><label>New Password</label><input type="password" name="password" required></div><div class="form-group"><label>Confirm New Password</label><input type="password" name="confirm_password" required></div><button class="btn btn-outline" type="submit">Change Password</button></form></div></div>
